def summarize_arthur_cook_career(text):
    """Extracts and summarizes Arthur Cook's political career from a given text."""
    positions = []
    lines = text.split('.')
    for line in lines:
        if 'justice' in line and ('Pennsylvania' in line or 'Supreme Court' in line):
            positions.append(line.strip())
        elif 'member of the' in line and 'Assembly' in line:
            positions.append(line.strip())
        elif 'commissioner' in line:
            positions.append(line.strip())
        elif 'speaker' in line:
            positions.append(line.strip())
    return '\n'.join(positions)

# Example usage:
text = "Arthur Cook was a justice of the Supreme Court of Pennsylvania..."
print(summarize_arthur_cook_career(text))

This function parses a text to extract Arthur Cook's political roles, including judicial, legislative, and administrative positions.
